sql:
SELECT auction_id, sale_price
FROM auctions
WHERE sale_price = (SELECT MAX(sale_price) FROM auctions);

SELECT auction_id, highest_bid
FROM auction_reports
ORDER BY highest_bid DESC;

SELECT auction_id, sale_price
FROM auctions
WHERE sale_price = (SELECT MAX(sale_price) FROM auctions);

SELECT COUNT(*) AS total_reports_with_bids
FROM auction_reports
WHERE total_bids IS NOT NULL;

SELECT auction_id, sale_price
FROM auctions
ORDER BY sale_price DESC;

SELECT SUM(cost) AS total_advertising_cost
  FROM advertising
  WHERE auction_id = 123;

SELECT auction_id, SUM(cost) AS total_advertising_cost
FROM advertising
GROUP BY auction_id;

external_knowledge:
- Lucrative deals refer to auctions where the profit is the highest; 
- Profit margin is calculated as sale price minus total advertising cost; 
- Advertising expenses are represented by the 'cost' table and are summed up for each auction.
